function calculate(inputs) {
  const { 
    personnelCount, 
    deploymentDurationDays, 
    primaryTransportMode, 
    distanceKm, 
    medicalSupplyWeightKg, 
    equipmentWeightKg, 
    avgMedicalSupplyCostPerKg,
    localLaborDailyCost, 
    securityDailyCost, 
    baseOperationalDailyCost, 
    contingencyPercentage 
  } = inputs;

  // Input validation and default values for robustness
  const safePersonnelCount = Math.max(0, personnelCount || 0);
  const safeDeploymentDurationDays = Math.max(0, deploymentDurationDays || 0);
  const safeDistanceKm = Math.max(0, distanceKm || 0);
  const safeMedicalSupplyWeightKg = Math.max(0, medicalSupplyWeightKg || 0);
  const safeEquipmentWeightKg = Math.max(0, equipmentWeightKg || 0);
  const safeAvgMedicalSupplyCostPerKg = Math.max(0, avgMedicalSupplyCostPerKg || 0);
  const safeLocalLaborDailyCost = Math.max(0, localLaborDailyCost || 0);
  const safeSecurityDailyCost = Math.max(0, securityDailyCost || 0);
  const safeBaseOperationalDailyCost = Math.max(0, baseOperationalDailyCost || 0);
  const safeContingencyPercentage = Math.max(0, Math.min(100, contingencyPercentage || 0)); // Cap at 100%

  // Constants for cost estimation (realistic benchmarks)
  const PERSONNEL_DAILY_RATE_USD = 450; // Includes salary, per diem, basic insurance per person

  // Transport cost factors (USD per kg per km) - illustrative, highly variable in reality
  const TRANSPORT_COST_PER_KG_KM = {
    airCargo: 0.25, // High speed, high cost
    seaFreight: 0.05, // Lower speed, lower cost
    groundConvoy: 0.12, // Medium speed/cost, dependent on infrastructure & security
    hybridComplex: 0.18 // Blended average for complex operations
  };

  // Base transport costs (USD) - fixed costs for mobilization/demobilization
  const TRANSPORT_BASE_COST = {
    airCargo: 15000,
    seaFreight: 25000,
    groundConvoy: 10000,
    hybridComplex: 30000
  };

  // Determine actual transport cost per kg per km and base cost
  const actualTransportCostPerKgKm = TRANSPORT_COST_PER_KG_KM[primaryTransportMode] || TRANSPORT_COST_PER_KG_KM.hybridComplex;
  const actualTransportBaseCost = TRANSPORT_BASE_COST[primaryTransportMode] || TRANSPORT_BASE_COST.hybridComplex;

  // 1. Calculate Personnel Cost
  const personnelCost = safePersonnelCount * PERSONNEL_DAILY_RATE_USD * safeDeploymentDurationDays;

  // 2. Calculate Medical Supply Purchase Cost
  const medicalSupplyPurchaseCost = safeMedicalSupplyWeightKg * safeAvgMedicalSupplyCostPerKg;

  // 3. Calculate Transport Cost
  const totalCargoWeightKg = safeMedicalSupplyWeightKg + safeEquipmentWeightKg;
  const variableTransportCost = totalCargoWeightKg * safeDistanceKm * actualTransportCostPerKgKm;
  const totalTransportCost = actualTransportBaseCost + variableTransportCost;

  // 4. Calculate Local Labor Cost
  const localLaborCost = safeLocalLaborDailyCost * safeDeploymentDurationDays;

  // 5. Calculate Security Cost
  const securityCost = safeSecurityDailyCost * safeDeploymentDurationDays;

  // 6. Calculate Base Operational Cost
  const baseOperationalCost = safeBaseOperationalDailyCost * safeDeploymentDurationDays;

  // 7. Calculate Subtotal Estimated Cost
  const subtotalEstimatedCost = 
    personnelCost +
    medicalSupplyPurchaseCost +
    totalTransportCost +
    localLaborCost +
    securityCost +
    baseOperationalCost;

  // 8. Calculate Contingency Fund
  const contingencyFund = subtotalEstimatedCost * (safeContingencyPercentage / 100);

  // 9. Calculate Grand Total Cost
  const grandTotalCost = subtotalEstimatedCost + contingencyFund;

  return {
    personnelCost: personnelCost,
    medicalSupplyPurchaseCost: medicalSupplyPurchaseCost,
    totalTransportCost: totalTransportCost,
    localLaborCost: localLaborCost,
    securityCost: securityCost,
    baseOperationalCost: baseOperationalCost,
    subtotalEstimatedCost: subtotalEstimatedCost,
    contingencyFund: contingencyFund,
    grandTotalCost: grandTotalCost
  };
}
